#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long powmod(long long a, long long b) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}

int main() {
    int n, k;
    scanf("%d %d", &n, &k);
    if (n % 2 == 1) {
        printf("0\n");
    } else {
        long long p = 1;
        long long q = 1;
        for (int i = 1; i <= n / 2; i++) {
            p = (p * (k - i + 1)) % MOD;
            q = (q * i) % MOD;
        }
        long long q_inv = powmod(q, MOD - 2);
        printf("%lld\n", (p * q_inv) % MOD);
    }
    return 0;
}

